(function () {
  'use strict';

  var EXEC_URL      = 'https://script.google.com/macros/s/AKfycbwNTbhz8bHrt66CWCqmrTGANyz_6CkO7K8M0blzAR0Sa8raRLu_K61vdCpGsVvBtDo9/exec';
  var TOKEN_KEY     = 'vency_seller_token';
  var SET_PRICE     = 12000;
  var SINGLE_DECANT = 5000;
  var B30_PRICE  = { 'disenador': 12000, 'nicho': 18000, 'ultra-nicho': 25000 };
  var B100_PRICE = { 'disenador': 25000, 'nicho': 35000, 'ultra-nicho': 50000 };
  var CAL_GREEN = 50000;
  var CAL_MILD  = 35000;
  var CAL_RED   = 20000;
  var PAGE_SIZE        = 12;
  var SALES_PREVIEW    = 5;
  var LOW_OIL_ML       = 30;
  var topFragranceName = null;
  var CONC_PRESETS     = [
    { label: 'EDC',    pct: 3  },
    { label: 'EDT',    pct: 10 },
    { label: 'EDP',    pct: 20 },
    { label: 'Parfum', pct: 35 },
    { label: 'Extrait',pct: 40 }
  ];

  function computeCapacity(oil_ml, pct) {
    if (!pct || pct <= 0) return { decant: 0, ml30: 0, ml100: 0 };
    var f = pct / 100;
    return { decant: Math.floor(oil_ml / (f * 10)), ml30: Math.floor(oil_ml / (f * 30)), ml100: Math.floor(oil_ml / (f * 100)) };
  }

  function concLabel(pct) {
    if (pct <= 0)  return '';
    if (pct <= 3)  return 'Eau Fra\xeeche';
    if (pct <= 5)  return 'EDC';
    if (pct <= 15) return 'EDT';
    if (pct <= 20) return 'EDP';
    if (pct <= 40) return 'Parfum';
    return 'Extrait';
  }

  var selection          = [];   // [{ id, name, invKey }]
  var bottles            = [];   // [{ id, name, fmt, price, invKey }]
  var token              = '';
  var activeMonth        = new Date();
  activeMonth.setDate(1);
  activeMonth.setHours(0, 0, 0, 0);
  var activePeriod       = 'hoy';
  var activeMode         = 'vender';
  var catalog            = [];
  var filteredCatalog    = [];
  var fragPage           = 0;
  var fragObserver       = null;
  var inventory          = {};
  var invFilteredCatalog = [];
  var invPage            = 0;
  var invObserver        = null;
  var _panelPrevFocus    = null;
  var calDailyTotals     = {};
  var selectedCalDay     = null;
  var allSales           = [];
  var monthSalesCache    = { month: null, sales: [] };

  var gate          = document.getElementById('js-gate');
  var gateForm      = document.getElementById('js-gate-form');
  var gateInput     = document.getElementById('js-gate-input');
  var gateBtn       = document.getElementById('js-gate-btn');
  var gateError     = document.getElementById('js-gate-error');
  var gateEye       = document.getElementById('js-gate-eye');
  var app           = document.getElementById('js-app');
  var metricsEl     = document.getElementById('js-metrics');
  var monthNavEl    = document.getElementById('js-month-nav');
  var monthPrevBtn  = document.getElementById('js-month-prev');
  var monthNextBtn  = document.getElementById('js-month-next');
  var monthLabelEl  = document.getElementById('js-month-label');
  var salesListEl      = document.getElementById('js-sales-list');
  var salesEmptyEl     = document.getElementById('js-sales-empty');
  var salesToggleBtn   = document.getElementById('js-sales-toggle');
  var salesToggleLblEl = document.getElementById('js-sales-toggle-label');
  var salesBodyEl      = document.getElementById('js-sales-body');
  var salesShowmoreBtn = document.getElementById('js-sales-showmore');
  var logoutBtn     = document.getElementById('js-logout');
  var installBtn    = document.getElementById('js-install');
  var searchInput   = document.getElementById('js-search');
  var fragList      = document.getElementById('js-frag-list');
  var fragSentinel  = document.getElementById('js-frag-sentinel');
  var invListEl     = document.getElementById('js-inv-list');
  var invSentinel   = document.getElementById('js-inv-sentinel');
  var invHintEl     = document.getElementById('js-inv-hint');
  var adminTrayEl   = document.getElementById('js-admin-tray');
  var traySlots     = document.getElementById('js-slots');
  var trayBottles   = document.getElementById('js-bottles-list');
  var totalEl       = document.getElementById('js-total');
  var openPanelBtn  = document.getElementById('js-open-panel');
  var adminPanelEl  = document.getElementById('js-admin-panel');
  var panelSheet    = document.getElementById('js-panel-sheet');
  var closePanelBtn = document.getElementById('js-close-panel');
  var panelSummary  = document.getElementById('js-panel-summary');
  var panelTotalEl  = document.getElementById('js-panel-total');
  var registerBtn   = document.getElementById('js-register');
  var noteEl        = document.getElementById('js-nota');
  var toastEl       = document.getElementById('js-toast');
  var modePanelVender = document.getElementById('js-mode-vender');
  var modePanelInv    = document.getElementById('js-mode-inventario');

  function colones(n) { return '₡' + Number(n).toLocaleString('es-CR'); }
  function generateRef() { return 'VA' + String(Math.floor(1000 + Math.random() * 9000)); }

  function cartTotal() {
    var decantAmt = selection.length === 3
      ? SET_PRICE
      : selection.length * SINGLE_DECANT;
    return decantAmt + bottles.reduce(function (s, b) { return s + b.price; }, 0);
  }

  function canRegister() { return selection.length > 0 || bottles.length > 0; }

  function buildItems() {
    var items = [];
    if (selection.length === 3) {
      var names = selection.map(function (s) {
        return s.name + (s.pct ? ' (' + s.pct + '%)' : '');
      }).join(', ');
      items.push({ label: 'Set de 3 Decants (10 ml): ' + names, price: SET_PRICE });
    } else {
      selection.forEach(function (s) {
        var c = s.pct ? ' \xb7 ' + concLabel(s.pct) + ' (' + s.pct + '%)' : '';
        items.push({ label: s.name + ' \xb7 Decant 10 ml' + c, price: SINGLE_DECANT });
      });
    }
    bottles.forEach(function (b) {
      var c = b.pct ? ' \xb7 ' + concLabel(b.pct) + ' (' + b.pct + '%)' : '';
      items.push({ label: b.name + ' \xb7 Frasco ' + (b.fmt === '30ml' ? '30 ml' : '100 ml') + c, price: b.price });
    });
    return items;
  }

  function formatMonthParam(d) {
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
  }

  function formatMonthDisplay(d) {
    return d.toLocaleDateString('es-CR', { month: 'long', year: 'numeric' }).toUpperCase();
  }

  function calGrade(total) {
    if (!total)             return 'empty';
    if (total >= CAL_GREEN) return 'hot';
    if (total >= CAL_MILD)  return 'warm';
    if (total >= CAL_RED)   return 'mild';
    return 'cold';
  }

  function calShort(n) {
    if (n >= 1000000) return '₡' + (n / 1000000).toFixed(1) + 'M';
    if (n >= 1000)    return '₡' + Math.round(n / 1000) + 'k';
    return '₡' + n;
  }

  function renderCalendar() {
    var calEl = document.getElementById('js-admin-cal');
    if (!calEl) return;

    var y   = activeMonth.getFullYear();
    var m   = activeMonth.getMonth();
    var now = new Date();

    var firstDow    = new Date(y, m, 1).getDay();
    var daysInMonth = new Date(y, m + 1, 0).getDate();

    function p2(n) { return n < 10 ? '0' + n : '' + n; }

    var DAY_HDR = ['D', 'L', 'M', 'X', 'J', 'V', 'S'];
    var calCollapsed = localStorage.getItem('vency_cal_collapsed') === '1';
    var html = '<button class="admin-cal__toggle js-cal-toggle" type="button" aria-expanded="' + !calCollapsed + '">'
      + '<span class="label">VENTAS POR DÍA</span>'
      + '<span class="admin-cal__scale">'
      + '<span class="admin-cal__pip admin-cal__pip--cold"></span>₡20k bajo'
      + '&ensp;<span class="admin-cal__pip admin-cal__pip--hot"></span>₡50k alto'
      + '</span>'
      + '<svg class="admin-cal__chevron" width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="3,5 7,9 11,5"/></svg>'
      + '</button>';

    html += '<div class="admin-cal__body"' + (calCollapsed ? ' hidden' : '') + '>';
    html += '<div class="admin-cal__grid" role="grid" aria-label="Ventas ' + formatMonthDisplay(activeMonth) + '">';

    DAY_HDR.forEach(function (d) {
      html += '<div class="admin-cal__hdr" role="columnheader">' + d + '</div>';
    });

    for (var f = 0; f < firstDow; f++) {
      html += '<div class="admin-cal__cell admin-cal__cell--filler" role="gridcell" aria-hidden="true"></div>';
    }

    for (var day = 1; day <= daysInMonth; day++) {
      var dk       = y + '-' + p2(m + 1) + '-' + p2(day);
      var total    = calDailyTotals[dk] || 0;
      var isFuture = new Date(y, m, day) > now;
      var isToday  = now.getFullYear() === y && now.getMonth() === m && now.getDate() === day;
      var grade    = isFuture ? 'future' : calGrade(total);
      var isSelected = selectedCalDay === dk;
      var cls = 'admin-cal__cell admin-cal__cell--' + grade
              + (isToday    ? ' admin-cal__cell--today'    : '')
              + (isSelected ? ' admin-cal__cell--selected' : '');
      var amtHtml  = (total > 0 && !isFuture) ? '<span class="admin-cal__amt">' + calShort(total) + '</span>' : '';
      html += '<div class="' + cls + '" role="gridcell" data-date="' + dk + '" aria-label="' + day
            + (total ? ' ' + colones(total) : ' sin ventas') + '">'
            + '<span class="admin-cal__day">' + day + '</span>'
            + amtHtml
            + '</div>';
    }

    html += '</div></div>';
    calEl.innerHTML = html;
    calEl.hidden = false;

    calEl.querySelector('.js-cal-toggle').addEventListener('click', function () {
      var body      = calEl.querySelector('.admin-cal__body');
      var collapsed = !body.hidden;
      body.hidden   = collapsed;
      this.setAttribute('aria-expanded', String(!collapsed));
      localStorage.setItem('vency_cal_collapsed', collapsed ? '1' : '0');
    });
  }

  function setupCalDayClick() {
    var calEl = document.getElementById('js-admin-cal');
    if (!calEl) return;
    calEl.addEventListener('click', function (e) {
      if (e.target.closest('.js-cal-toggle')) return;
      var cell = e.target.closest('[data-date]');
      if (!cell) return;
      var dk = cell.dataset.date;
      selectedCalDay = selectedCalDay === dk ? null : dk;
      renderCalendar();

      if (!selectedCalDay) {
        renderSalesList(allSales);
        return;
      }

      salesBodyEl.hidden = false;
      salesBodyEl.getBoundingClientRect();
      salesBodyEl.classList.add('is-open');
      if (salesToggleBtn) {
        salesToggleBtn.setAttribute('aria-expanded', 'true');
        salesToggleBtn.classList.add('is-open');
      }
      if (salesToggleBtn) salesToggleBtn.scrollIntoView({ behavior: 'smooth', block: 'start' });

      var dk = selectedCalDay;
      if (monthSalesCache.month === activeMonth) {
        renderSalesList(monthSalesCache.sales.filter(function (s) { return s.fecha === dk; }));
      } else {
        fetch(EXEC_URL, {
          method: 'POST',
          body: JSON.stringify({ action: 'summary', token: token, period: 'mes', month: formatMonthParam(activeMonth) })
        })
        .then(function (r) { return r.json(); })
        .then(function (d) {
          monthSalesCache = { month: activeMonth, sales: d.sales || [] };
          renderSalesList(monthSalesCache.sales.filter(function (s) { return s.fecha === dk; }));
        })
        .catch(function () {});
      }
    });
  }

  function filterSales() {
    if (!selectedCalDay) return allSales;
    return allSales.filter(function (s) { return s.fecha === selectedCalDay; });
  }

  function isLightColor(oklchStr) {
    var m = /oklch\(\s*([\d.]+)%/.exec(oklchStr || '');
    return m ? parseFloat(m[1]) > 55 : false;
  }

  function buildCatalog() {
    var vency = (window.VENCY_CATALOG || []).map(function (f) {
      return {
        _type: 'vency',
        id: f.id,
        name: f.name,
        soldOut: !!f.soldOut,
        image: f.image || null,
        characterColor: f.characterColor || null
      };
    });
    var ext = (window.VENCY_FULL_CATALOG || []).map(function (f, i) {
      return { _type: 'decant', id: 'ext-' + i, name: f.name, brand: f.brand || '', cat: f.cat };
    });
    catalog = vency.concat(ext);
  }

  function invKey(frag, fmt) {
    if (frag._type === 'vency') return frag.id + ':' + fmt;
    return (frag.brand || '') + '|' + frag.name + ':' + fmt;
  }

  function getToken()   { return localStorage.getItem(TOKEN_KEY) || ''; }
  function saveToken(t) { localStorage.setItem(TOKEN_KEY, t); }
  function clearToken() { localStorage.removeItem(TOKEN_KEY); }

  function escapeHtml_(str) {
    var div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  function showGate() {
    gate.hidden = false;
    app.hidden  = true;
    app.classList.remove('is-visible');
    gateError.hidden    = true;
    gateInput.value     = '';
    gateBtn.disabled    = false;
    gateBtn.textContent = 'Entrar';
    setTimeout(function () { gateInput.focus(); }, 80);
  }

  function showApp(t) {
    token = t;
    gate.hidden = false;
    app.hidden  = false;
    gate.hidden = true;
    app.getBoundingClientRect();
    app.classList.add('is-visible');
    window.scrollTo(0, 0);
    setupPeriodTabs();
    setupModeTabs();
    monthNavEl.hidden = activePeriod !== 'mes';
    updateMonthNav();
    renderCalendar();
    setupCalDayClick();
    renderFragList('');
    renderInvList('');
    loadMetrics();
    loadInventory();
    setInterval(loadMetrics, 60000);
    if (salesToggleBtn) salesToggleBtn.addEventListener('click', toggleSalesSection);
    if (salesShowmoreBtn) salesShowmoreBtn.addEventListener('click', showAllSales);

    if (salesListEl) salesListEl.addEventListener('click', function (e) {
      var moreBtn = e.target.closest('.sale-row__more');
      if (moreBtn) {
        var row = moreBtn.closest('.sale-row');
        var expanded = row.classList.toggle('is-expanded');
        moreBtn.textContent = expanded ? 'ver menos' : 'ver m\xe1s';
        return;
      }
      var confBtn   = e.target.closest('.sale-row__confirm');
      if (confBtn) { confirmSale(confBtn); return; }
      var cancelBtn = e.target.closest('.sale-row__cancel');
      if (cancelBtn) { cancelOrder(cancelBtn); return; }
      var abortBtn = e.target.closest('.sale-row__cancel-abort');
      if (abortBtn) abortCancel(abortBtn);
    });
  }

  function showGateError() {
    gateError.hidden = false;
    gateError.classList.remove('is-shaking');
    gateError.getBoundingClientRect();
    gateError.classList.add('is-shaking');
    gateError.addEventListener('animationend', function () {
      gateError.classList.remove('is-shaking');
    }, { once: true });
  }

  function validateToken(t, cb) {
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'summary', token: t, month: formatMonthParam(activeMonth) })
    })
    .then(function (r) { return r.text(); })
    .then(function (txt) {
      try {
        var d = JSON.parse(txt);
        cb(typeof d.today === 'number' || typeof d.month === 'number');
      } catch (e) { cb(false); }
    })
    .catch(function () { cb(false); });
  }

  gateForm.addEventListener('submit', function (e) {
    e.preventDefault();
    var entered = gateInput.value.trim();
    if (!entered) return;
    gateError.hidden    = true;
    gateBtn.disabled    = true;
    gateBtn.textContent = 'Validando...';
    validateToken(entered, function (ok) {
      if (ok) { saveToken(entered); showApp(entered); }
      else {
        gateBtn.disabled    = false;
        gateBtn.textContent = 'Entrar';
        showGateError();
        gateInput.select();
      }
    });
  });

  gateEye.addEventListener('click', function () {
    var showing = gateInput.type === 'text';
    gateInput.type = showing ? 'password' : 'text';
    gateEye.setAttribute('aria-label', showing ? 'Mostrar contraseña' : 'Ocultar contraseña');
    gateEye.querySelector('svg').innerHTML = showing
      ? '<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>'
      : '<path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/>';
  });

  var _installPrompt = null;
  window.addEventListener('beforeinstallprompt', function (e) {
    e.preventDefault();
    _installPrompt = e;
    installBtn.hidden = false;
  });
  installBtn.addEventListener('click', function () {
    if (!_installPrompt) return;
    _installPrompt.prompt();
    _installPrompt.userChoice.then(function () {
      _installPrompt = null;
      installBtn.hidden = true;
    });
  });
  window.addEventListener('appinstalled', function () { installBtn.hidden = true; });

  logoutBtn.addEventListener('click', function () {
    clearToken();
    selection = []; bottles = [];
    closePanel(true);
    adminTrayEl.hidden = true;
    showGate();
  });

  var scrollTopBtn = document.getElementById('js-scroll-top');
  window.addEventListener('scroll', function () {
    scrollTopBtn.hidden = window.scrollY < 300;
  }, { passive: true });
  scrollTopBtn.addEventListener('click', function () {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });

  function updateMonthNav() {
    var now      = new Date();
    var nowStart = new Date(now.getFullYear(), now.getMonth(), 1);
    monthLabelEl.textContent = formatMonthDisplay(activeMonth);
    monthNextBtn.disabled    = activeMonth >= nowStart;
  }

  monthPrevBtn.addEventListener('click', function () {
    activeMonth = new Date(activeMonth.getFullYear(), activeMonth.getMonth() - 1, 1);
    updateMonthNav();
    loadMetrics();
  });

  monthNextBtn.addEventListener('click', function () {
    var now      = new Date();
    var nowStart = new Date(now.getFullYear(), now.getMonth(), 1);
    var next     = new Date(activeMonth.getFullYear(), activeMonth.getMonth() + 1, 1);
    if (next <= nowStart) { activeMonth = next; updateMonthNav(); loadMetrics(); }
  });

  var PERIOD_LABELS = { hoy: 'HOY', semana: 'ESTA SEMANA', mes: 'ESTE MES' };

  function setupPeriodTabs() {
    var tabs = document.querySelectorAll('.metrics__period-tab');
    Array.prototype.forEach.call(tabs, function (tab) {
      tab.addEventListener('click', function () {
        activePeriod = tab.dataset.period;
        Array.prototype.forEach.call(tabs, function (t) {
          t.classList.toggle('metrics__period-tab--active', t === tab);
          t.setAttribute('aria-selected', String(t === tab));
        });
        monthNavEl.hidden = activePeriod !== 'mes';
        loadMetrics();
      });
    });
    var refreshBtn = document.getElementById('js-refresh');
    if (refreshBtn) refreshBtn.addEventListener('click', function () {
      refreshBtn.classList.add('metrics__refresh-btn--spin');
      loadMetrics();
      setTimeout(function () { refreshBtn.classList.remove('metrics__refresh-btn--spin'); }, 600);
    });
  }

  function setupModeTabs() {
    var tabs = document.querySelectorAll('.mode-tab');
    Array.prototype.forEach.call(tabs, function (tab) {
      tab.addEventListener('click', function () {
        activeMode = tab.dataset.mode;
        Array.prototype.forEach.call(tabs, function (t) {
          t.classList.toggle('mode-tab--active', t === tab);
          t.setAttribute('aria-selected', String(t === tab));
        });
        modePanelVender.hidden = activeMode !== 'vender';
        modePanelInv.hidden    = activeMode !== 'inventario';
        searchInput.value = '';
        if (activeMode === 'vender') renderFragList('');
        else renderInvList('');
      });
    });
  }

  function loadMetrics() {
    var offline   = document.getElementById('js-metrics-offline');
    var periodLbl = document.getElementById('js-period-label');
    var periodVal = document.getElementById('js-metric-period');
    metricsEl.classList.add('loading');
    if (periodLbl) periodLbl.textContent = PERIOD_LABELS[activePeriod] || activePeriod.toUpperCase();
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'summary', token: token, period: activePeriod, month: formatMonthParam(activeMonth) })
    })
    .then(function (r) { return r.json(); })
    .then(function (d) {
      metricsEl.classList.remove('loading');
      offline.hidden = true;
      if (periodVal) periodVal.textContent = colones(d.month || 0);
      document.getElementById('js-metric-web').textContent      = colones(d.web      || 0);
      document.getElementById('js-metric-local').textContent    = colones(d.local    || 0);
      document.getElementById('js-metric-efectivo').textContent = colones(d.efectivo || 0);
      document.getElementById('js-metric-sinpe').textContent    = colones(d.sinpe    || 0);
      var pendEl = document.getElementById('js-metric-web-pending');
      if (pendEl) {
        pendEl.hidden      = !(d.webPendiente > 0);
        pendEl.textContent = d.webPendiente > 0 ? colones(d.webPendiente) + ' sin confirmar' : '';
      }
      renderTop(d.fragrances || {});
      allSales = d.sales || [];
      calDailyTotals = d.daily || {};
      if (activePeriod === 'mes') {
        monthSalesCache = { month: activeMonth, sales: allSales };
      }
      renderCalendar();
      renderSalesList(filterSales());
    })
    .catch(function (err) {
      metricsEl.classList.remove('loading');
      offline.hidden = false;
      console.error('[Metrics load failed]', err);
      if (refreshBtn) refreshBtn.disabled = false;
    });
  }

  function renderTop(fragrances) {
    var topEl   = document.getElementById('js-metric-top');
    var entries = Object.keys(fragrances).map(function (k) { return { name: k, count: fragrances[k] }; });
    if (!entries.length) { topEl.textContent = ''; topFragranceName = null; return; }
    entries.sort(function (a, b) { return b.count - a.count; });
    topFragranceName = entries[0].name;
    topEl.innerHTML = '<strong>Top:</strong> ' + entries.slice(0, 3).map(function (e) {
      return escapeHtml_(e.name) + ' \xd7' + e.count;
    }).join(' \xb7 ');
  }

  function renderSalesList(sales) {
    if (!salesListEl || !salesEmptyEl) return;
    salesListEl.innerHTML = '';

    if (salesToggleLblEl) {
      var pendingCount = sales.filter(function (s) { return s.estado === 'pendiente'; }).length;
      var labelParts;
      if (selectedCalDay) {
        var cd = new Date(selectedCalDay + 'T12:00:00');
        labelParts = [cd.toLocaleDateString('es-CR', { day: 'numeric', month: 'long' }).toUpperCase()];
      } else {
        labelParts = ['PEDIDOS'];
      }
      if (sales.length) {
        labelParts.push(sales.length + (sales.length === 1 ? ' venta' : ' ventas'));
        if (pendingCount) labelParts.push(pendingCount + ' por confirmar');
      }
      salesToggleLblEl.textContent = labelParts.join('\xa0\xb7\xa0');
    }

    if (!sales.length) {
      salesEmptyEl.hidden = false;
      salesListEl.hidden  = true;
      if (salesShowmoreBtn) salesShowmoreBtn.hidden = true;
      return;
    }
    salesEmptyEl.hidden = true;
    salesListEl.hidden  = false;
    var pagoClass = { 'SINPE': 'sinpe', 'Efectivo': 'efectivo' };
    sales.forEach(function (s, idx) {
      var isPending  = s.estado === 'pendiente';
      var isOverflow = idx >= SALES_PREVIEW;
      var row = document.createElement('div');
      row.className = 'sale-row' + (isPending ? ' sale-row--pending' : '') + (isOverflow ? ' sale-row--overflow' : '');
      row.hidden    = isOverflow;
      row.dataset.ref = s.ref;
      var pc      = pagoClass[s.pago] || '';
      var rawParts = s.raw ? s.raw.split(' | ') : [];
      var hasMore  = rawParts.length > 1 || (s.raw && s.raw.length > s.items.length + 2);
      var fullHtml = hasMore
        ? rawParts.map(function (p) { return '<span class="sale-row__item-line">' + p.trim() + '</span>'; }).join('')
        : '';
      row.innerHTML =
        '<span class="sale-row__ref">'  + escapeHtml_(s.ref)  + '</span>' +
        '<span class="sale-row__hora">' + escapeHtml_(s.hora) + '</span>' +
        '<span class="sale-row__items">' +
          '<span class="sale-row__items-preview">' + escapeHtml_(s.items) + '</span>' +
          (hasMore
            ? '<span class="sale-row__items-full"><span class="sale-row__items-full__inner">' + fullHtml + '</span></span>' +
              '<button class="sale-row__more" type="button">ver m\xe1s</button>'
            : '') +
        '</span>' +
        '<span class="sale-row__meta">' +
          '<span class="sale-row__total">'                           + colones(s.total) + '</span>' +
          '<span class="sale-row__pago sale-row__pago--' + pc + '">' + s.pago           + '</span>' +
          '<div class="sale-row__actions">' +
            '<button class="sale-row__cancel" type="button" aria-label="Eliminar pedido ' + s.ref + '">Eliminar</button>' +
            '<button class="sale-row__cancel-abort" type="button" hidden aria-label="No, cancelar eliminaci\xf3n">No</button>' +
            (isPending ? '<button class="sale-row__confirm" type="button" aria-label="Confirmar pedido ' + s.ref + '">Confirmar</button>' : '') +
          '</div>' +
        '</span>';
      salesListEl.appendChild(row);
    });

    if (salesShowmoreBtn) {
      var overflow = sales.length - SALES_PREVIEW;
      salesShowmoreBtn.hidden = overflow <= 0;
      if (overflow > 0) {
        salesShowmoreBtn.textContent = 'Ver ' + overflow + ' m\xe1s';
      }
    }
  }

  function confirmSale(btn) {
    var row = btn.closest('.sale-row');
    var ref = row && row.dataset.ref;
    if (!ref) return;
    btn.disabled    = true;
    btn.textContent = '…';
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'confirm', token: token, ref: ref })
    })
    .then(function (r) { return r.text(); })
    .then(function (txt) {
      if (txt.trim() === 'ok') {
        row.classList.remove('sale-row--pending');
        btn.remove();
        showToast('Pedido ' + ref + ' confirmado');
        loadMetrics();
      } else {
        btn.disabled    = false;
        btn.textContent = 'Confirmar';
        showToast('Error (' + txt.trim() + '). Intent\xe1 de nuevo.', true);
      }
    })
    .catch(function () {
      btn.disabled    = false;
      btn.textContent = 'Confirmar';
      showToast('Sin conexi\xf3n. Intent\xe1 de nuevo.', true);
    });
  }

  function _armCancel(btn) {
    var actions = btn.closest('.sale-row__actions');
    var armRow  = btn.closest('.sale-row');
    btn.textContent = 'S\xed, eliminar';
    btn.setAttribute('aria-label', 'S\xed, eliminar pedido ' + (armRow ? armRow.dataset.ref : ''));
    btn.classList.add('sale-row__cancel--armed');
    var abort   = actions && actions.querySelector('.sale-row__cancel-abort');
    var confirm = actions && actions.querySelector('.sale-row__confirm');
    if (abort)   abort.hidden   = false;
    if (confirm) confirm.hidden = true;
    btn._cancelTimer = setTimeout(function () { abortCancel(abort || btn); }, 3500);
  }

  function abortCancel(ref) {

    var actions = ref.closest('.sale-row__actions');
    if (!actions) return;
    var cancelBtn = actions.querySelector('.sale-row__cancel');
    var abortBtn  = actions.querySelector('.sale-row__cancel-abort');
    var confBtn   = actions.querySelector('.sale-row__confirm');
    clearTimeout(cancelBtn && cancelBtn._cancelTimer);
    if (cancelBtn) {
      var abortRow = cancelBtn.closest('.sale-row');
      cancelBtn.textContent = 'Eliminar';
      cancelBtn.setAttribute('aria-label', 'Eliminar pedido ' + (abortRow ? abortRow.dataset.ref : ''));
      cancelBtn.classList.remove('sale-row__cancel--armed');
      cancelBtn.disabled = false;
    }
    if (abortBtn)  abortBtn.hidden  = true;
    if (confBtn)   confBtn.hidden   = false;
  }

  function cancelOrder(btn) {
    var row = btn.closest('.sale-row');
    var ref = row && row.dataset.ref;
    if (!ref) return;
    if (!btn.classList.contains('sale-row__cancel--armed')) {
      _armCancel(btn);
      return;
    }

    clearTimeout(btn._cancelTimer);
    var actions = btn.closest('.sale-row__actions');
    if (actions) actions.querySelectorAll('button').forEach(function (b) { b.disabled = true; });
    btn.textContent = '…';
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'cancel', token: token, ref: ref })
    })
    .then(function (r) { return r.text(); })
    .then(function (txt) {
      if (txt.trim() === 'ok') {
        row.remove();
        showToast('Pedido ' + ref + ' eliminado');
        loadMetrics();
        loadInventory();
      } else {
        abortCancel(btn);
        showToast('Error (' + txt.trim() + '). Intent\xe1 de nuevo.', true);
      }
    })
    .catch(function () {
      abortCancel(btn);
      showToast('Sin conexi\xf3n. Intent\xe1 de nuevo.', true);
    });
  }

  function toggleSalesSection() {
    var isOpen = !salesBodyEl.hidden;
    if (isOpen) {
      salesBodyEl.classList.remove('is-open');
      salesBodyEl.addEventListener('transitionend', function () {
        salesBodyEl.hidden = true;
      }, { once: true });
      salesToggleBtn.setAttribute('aria-expanded', 'false');
      salesToggleBtn.classList.remove('is-open');
    } else {
      salesBodyEl.hidden = false;
      salesBodyEl.getBoundingClientRect();
      salesBodyEl.classList.add('is-open');
      salesToggleBtn.setAttribute('aria-expanded', 'true');
      salesToggleBtn.classList.add('is-open');
    }
  }

  function showAllSales() {
    salesListEl.querySelectorAll('.sale-row--overflow').forEach(function (row) {
      row.classList.remove('sale-row--overflow');
      row.hidden = false;
    });
    salesShowmoreBtn.hidden = true;
  }

  function loadInventory() {
    invHintEl.textContent = 'Cargando inventario...';
    invHintEl.hidden = false;
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'inventory', token: token })
    })
    .then(function (r) { return r.json(); })
    .then(function (d) {
      inventory = d || {};
      invHintEl.hidden = true;
      syncFragBtns();
      syncInvDisplay();
      renderInvList(searchInput.value);
    })
    .catch(function () {
      invHintEl.textContent = 'Sin conexi\xf3n — inventario no disponible.';
    });
  }

  function batchUpdateStock(updates) {
    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'stock', token: token, updates: updates })
    })
    .then(function (r) { return r.text(); })
    .then(function (txt) {
      if (txt.trim() !== 'ok') showToast('Stock no se guard\xf3 (' + txt.trim() + ')', true);
    })
    .catch(function () { showToast('Sin conexi\xf3n — stock no guardado', true); });
  }

  function decrementSaleStock() {
    var updates = [];
    selection.forEach(function (s) {
      if (!inventory[s.id] || !s.pct) return;
      var delta_ml = -(s.pct / 100) * 10;
      inventory[s.id].oil_ml = Math.max(0, (inventory[s.id].oil_ml || 0) + delta_ml);
      updates.push({ key: s.id, delta_ml: delta_ml });
    });
    bottles.forEach(function (b) {
      if (!inventory[b.id] || !b.pct) return;
      var fmtMl    = b.fmt === '30ml' ? 30 : 100;
      var delta_ml = -(b.pct / 100) * fmtMl;
      inventory[b.id].oil_ml = Math.max(0, (inventory[b.id].oil_ml || 0) + delta_ml);
      updates.push({ key: b.id, delta_ml: delta_ml });
    });
    if (updates.length) batchUpdateStock(updates);
  }

  fragList.addEventListener('click', function (e) {
    var btn = e.target.closest('button');
    if (!btn) return;
    if (btn.classList.contains('js-decant-btn'))
      toggleDecant(btn.dataset.id, btn.dataset.name, btn.dataset.invkey);
    if (btn.classList.contains('js-bottle-btn'))
      toggleBottle(btn.dataset.id, btn.dataset.name, btn.dataset.fmt,
        btn.dataset.price ? parseInt(btn.dataset.price, 10) : undefined,
        btn.dataset.invkey);
  });

  function buildFragRow(frag) {
    var el = document.createElement('div');

    if (frag._type === 'vency') {
      var dk       = invKey(frag, 'decant');
      var bk30     = invKey(frag, '30ml');
      var bk100    = invKey(frag, '100ml');
      var vb30Price  = 12000;
      var vb100Price = 20000;
      var color = frag.characterColor || 'oklch(28% 0.04 180)';
      var light = isLightColor(color);

      el.className = 'dblock dblock--admin' + (light ? ' dblock--admin-light' : '');
      el.style.cssText = '--dblock-color:' + color;

      var imgHtml = frag.image
        ? '<div class="dblock__img-wrap"><img src="' + frag.image + '" alt="" loading="lazy"></div>'
        : '';

      el.innerHTML =
        '<div class="dblock__top">' +
          imgHtml +
          '<div class="dblock__content"><h3 class="dblock__name">' + escapeHtml_(frag.name) + '</h3></div>' +
          '<button class="dblock__trigger js-decant-btn"' +
            (frag.soldOut ? ' disabled' : '') +
            ' data-id="' + escapeHtml_(frag.id) + '" data-name="' + escapeHtml_(frag.name) + '" data-invkey="' + escapeHtml_(dk) + '"' +
            ' type="button" aria-label="' + escapeHtml_(frag.name) + (frag.soldOut ? ' \xb7 Agotado"' : '"') + '>' +
          '</button>' +
        '</div>' +
        '<div class="dblock__footer admin-fmt-rail">' +
          '<button class="admin-fmt-btn js-bottle-btn" data-id="' + escapeHtml_(frag.id) + '" data-name="' + escapeHtml_(frag.name) + '" data-fmt="30ml" data-price="' + vb30Price + '" data-invkey="' + escapeHtml_(bk30) + '" type="button">30ML</button>' +
          '<button class="admin-fmt-btn js-bottle-btn" data-id="' + escapeHtml_(frag.id) + '" data-name="' + escapeHtml_(frag.name) + '" data-fmt="100ml" data-price="' + vb100Price + '" data-invkey="' + escapeHtml_(bk100) + '" type="button">100ML</button>' +
        '</div>';

      if (frag.soldOut) el.classList.add('dblock--soldout');

    } else {
      var b30Price  = B30_PRICE[frag.cat]  || B30_PRICE['disenador'];
      var b100Price = B100_PRICE[frag.cat] || B100_PRICE['disenador'];
      var fullName  = (frag.brand ? frag.brand + ' ' : '') + frag.name;
      var dKey      = invKey(frag, 'decant');
      var b30Key    = invKey(frag, '30ml');
      var b100Key   = invKey(frag, '100ml');
      var catCls    = 'dblock--ext-' + (frag.cat || 'disenador');

      el.className = 'dblock dblock--admin ' + catCls;
      el.innerHTML =
        '<div class="dblock__top">' +
          '<div class="dblock__content">' +
            (frag.brand ? '<span class="dblock__brand">' + escapeHtml_(frag.brand) + '</span>' : '') +
            '<h3 class="dblock__name">' + escapeHtml_(frag.name) + '</h3>' +
          '</div>' +
          '<button class="dblock__trigger js-decant-btn" data-id="' + escapeHtml_(frag.id) + '" data-name="' + escapeHtml_(fullName) + '" data-invkey="' + escapeHtml_(dKey) + '" type="button" aria-label="' + escapeHtml_(fullName) + ' \xb7 Decant"></button>' +
        '</div>' +
        '<div class="dblock__footer admin-fmt-rail">' +
          '<button class="admin-fmt-btn js-bottle-btn" data-id="' + frag.id + '" data-name="' + fullName + '" data-fmt="30ml" data-price="' + b30Price + '" data-invkey="' + b30Key + '" type="button">30ML</button>' +
          '<button class="admin-fmt-btn js-bottle-btn" data-id="' + frag.id + '" data-name="' + fullName + '" data-fmt="100ml" data-price="' + b100Price + '" data-invkey="' + b100Key + '" type="button">100ML</button>' +
        '</div>';
    }

    return el;
  }

  function appendFragPage() {
    var start = fragPage * PAGE_SIZE;
    var slice = filteredCatalog.slice(start, start + PAGE_SIZE);
    var frag  = document.createDocumentFragment();
    slice.forEach(function (f) { frag.appendChild(buildFragRow(f)); });
    fragList.appendChild(frag);
    fragPage++;
    syncFragBtns();
    if (fragPage * PAGE_SIZE >= filteredCatalog.length && fragObserver) {
      fragObserver.disconnect();
      fragObserver = null;
    }
  }

  function renderFragList(query) {
    var q = (query || '').trim().toLowerCase();
    filteredCatalog = catalog.filter(function (f) {
      if (!q) return true;
      var t = f.name.toLowerCase() + (f.brand ? ' ' + f.brand.toLowerCase() : '');
      return t.indexOf(q) !== -1;
    });

    fragPage = 0;
    fragList.innerHTML = '';

    if (!filteredCatalog.length) {
      var empty = document.createElement('p');
      empty.className = 'dblock-empty';
      empty.textContent = q ? 'Sin resultados para "' + query + '".' : 'No hay fragancias.';
      fragList.appendChild(empty);
      return;
    }

    if (fragObserver) { fragObserver.disconnect(); fragObserver = null; }
    appendFragPage();

    if (filteredCatalog.length > PAGE_SIZE) {
      fragObserver = new IntersectionObserver(function (entries) {
        if (entries[0].isIntersecting) appendFragPage();
      }, { rootMargin: '120px' });
      fragObserver.observe(fragSentinel);
    }
  }

  searchInput.addEventListener('input', function () {
    if (activeMode === 'vender') renderFragList(this.value);
    else renderInvList(this.value);
  });
  searchInput.addEventListener('search', function () {
    if (activeMode === 'vender') renderFragList(this.value);
    else renderInvList(this.value);
  });

  function defaultPct(id) {
    return (inventory[id] && inventory[id].pct) || 20;
  }

  function toggleDecant(id, name, ik) {
    var idx = selection.findIndex(function (s) { return s.id === id; });
    if (idx !== -1) { selection.splice(idx, 1); }
    else {
      var item = { id: id, name: name, invKey: ik, pct: defaultPct(id) };
      if (selection.length < 3) selection.push(item);
      else selection[2] = item;
    }
    syncCart();
  }

  function toggleBottle(id, name, fmt, priceOverride, ik) {
    var idx = bottles.findIndex(function (b) { return b.id === id && b.fmt === fmt; });
    if (idx !== -1) { bottles.splice(idx, 1); }
    else {
      var price = priceOverride !== undefined ? priceOverride : 12000;
      bottles.push({ id: id, name: name, fmt: fmt, price: price, invKey: ik, pct: defaultPct(id) });
    }
    syncCart();
  }

  function syncCart() {
    syncTray();
    syncFragBtns();
    var total = cartTotal();
    totalEl.textContent      = colones(total);
    panelTotalEl.textContent = colones(total);
    registerBtn.disabled     = !canRegister();
    adminTrayEl.hidden       = !canRegister();
  }

  function syncTray() {
    traySlots.innerHTML = '';
    selection.forEach(function (s, i) {
      var chip = document.createElement('button');
      chip.className   = 'admin-tray__slot-chip';
      chip.textContent = s.name;
      chip.dataset.idx = i;
      chip.type        = 'button';
      chip.title       = 'Quitar ' + s.name;
      chip.setAttribute('aria-label', 'Quitar ' + s.name);
      traySlots.appendChild(chip);
    });

    trayBottles.innerHTML = '';
    bottles.forEach(function (b, i) {
      var chip = document.createElement('button');
      chip.className   = 'admin-tray__bottle-chip';
      chip.textContent = b.name.split(' ')[0] + ' \xb7 ' + b.fmt;
      chip.dataset.idx = i;
      chip.type        = 'button';
      chip.title       = 'Quitar ' + b.name;
      chip.setAttribute('aria-label', 'Quitar ' + b.name);
      trayBottles.appendChild(chip);
    });
  }

  traySlots.addEventListener('click', function (e) {
    var chip = e.target.closest('.admin-tray__slot-chip');
    if (!chip) return;
    selection.splice(Number(chip.dataset.idx), 1);
    syncCart();
  });

  trayBottles.addEventListener('click', function (e) {
    var chip = e.target.closest('.admin-tray__bottle-chip');
    if (!chip) return;
    bottles.splice(Number(chip.dataset.idx), 1);
    syncCart();
  });

  function syncFragBtns() {
    fragList.querySelectorAll('.dblock--admin').forEach(function (card) {
      var trigger = card.querySelector('.js-decant-btn');
      if (!trigger) return;
      var id     = trigger.dataset.id;
      var inCart = selection.some(function (s) { return s.id === id; });
      card.classList.toggle('dblock--selected', inCart);
      card.classList.toggle('dblock--dimmed', selection.length === 3 && !inCart);

      if (!card.classList.contains('dblock--soldout')) {
        var entry = inventory[id];
        var noStock = entry && entry.pct > 0 && computeCapacity(entry.oil_ml || 0, entry.pct).decant === 0;
        trigger.disabled = !inCart && noStock;
      }

      card.querySelectorAll('.js-bottle-btn').forEach(function (btn) {
        var inB   = bottles.some(function (b) { return b.id === id && b.fmt === btn.dataset.fmt; });
        btn.classList.toggle('admin-fmt-btn--active', inB);
        var entry = inventory[id];
        if (entry && entry.pct > 0) {
          var cap    = computeCapacity(entry.oil_ml || 0, entry.pct);
          var fmtCap = btn.dataset.fmt === '30ml' ? cap.ml30 : cap.ml100;
          btn.disabled = !inB && fmtCap === 0;
        }
      });
    });
  }

  function openPanel() {
    _panelPrevFocus = document.activeElement;
    syncPanelSummary();
    adminPanelEl.hidden = false;
    panelSheet.classList.remove('is-closing');
    closePanelBtn.focus();
  }

  function closePanel(immediate) {
    if (adminPanelEl.hidden) return;
    function restoreFocus() { if (_panelPrevFocus) _panelPrevFocus.focus(); }
    if (immediate) { adminPanelEl.hidden = true; restoreFocus(); return; }
    panelSheet.classList.add('is-closing');
    panelSheet.addEventListener('animationend', function () {
      adminPanelEl.hidden = true;
      panelSheet.classList.remove('is-closing');
      restoreFocus();
    }, { once: true });
  }

  adminPanelEl.addEventListener('keydown', function (e) {
    if (e.key !== 'Tab' || adminPanelEl.hidden) return;
    var focusable = Array.prototype.slice.call(
      panelSheet.querySelectorAll('button:not(:disabled), input:not(:disabled), [tabindex]:not([tabindex="-1"])')
    ).filter(function (el) { return !el.hidden; });
    if (!focusable.length) return;
    var first = focusable[0];
    var last  = focusable[focusable.length - 1];
    if (e.shiftKey) {
      if (document.activeElement === first) { e.preventDefault(); last.focus(); }
    } else {
      if (document.activeElement === last)  { e.preventDefault(); first.focus(); }
    }
  });

  function concPickerHtml(activePct, type, idx) {
    return '<div class="conc-picker" role="group" aria-label="Concentraci\xf3n">' +
      CONC_PRESETS.map(function (p) {
        return '<button class="conc-btn' + (p.pct === activePct ? ' conc-btn--active' : '') + '"' +
          ' type="button" data-pct="' + p.pct + '" data-type="' + type + '" data-idx="' + idx + '">' +
          p.label + '</button>';
      }).join('') +
    '</div>';
  }

  function oilCostHtml(pct, volMl, type, idx) {
    var ml = pct ? ((pct / 100) * volMl).toFixed(1) : '0';
    return '<span class="conc-oil-cost js-oil-cost" data-type="' + type + '" data-idx="' + idx + '">' +
      ml + ' ml aceite</span>';
  }

  function syncPanelSummary() {
    panelSummary.innerHTML = '';
    var isSet = selection.length === 3;

    if (isSet) {
      var hdr = document.createElement('div');
      hdr.className = 'admin-panel__set-row';
      hdr.innerHTML = '<span>Set de 3 Decants (10 ml)</span>' +
        '<span class="admin-panel__line-price">' + colones(SET_PRICE) + '</span>';
      panelSummary.appendChild(hdr);
    }

    selection.forEach(function (s, idx) {
      var el = document.createElement('div');
      el.className = 'admin-panel__item' + (isSet ? ' admin-panel__item--set' : '');
      el.dataset.type = 'decant'; el.dataset.idx = idx;
      var hasInv = !!inventory[s.id];
      el.innerHTML =
        '<div class="panel-item__head">' +
          '<span class="panel-item__name">' + escapeHtml_(s.name) + '</span>' +
          (!isSet ? '<span class="admin-panel__line-price">' + colones(SINGLE_DECANT) + '</span>' : '') +
        '</div>' +
        (hasInv ? concPickerHtml(s.pct, 'decant', idx) + oilCostHtml(s.pct, 10, 'decant', idx) : '');
      panelSummary.appendChild(el);
    });

    bottles.forEach(function (b, idx) {
      var el = document.createElement('div');
      el.className = 'admin-panel__item';
      el.dataset.type = 'bottle'; el.dataset.idx = idx;
      var fmtMl  = b.fmt === '30ml' ? 30 : 100;
      var hasInv = !!inventory[b.id];
      el.innerHTML =
        '<div class="panel-item__head">' +
          '<div><span class="panel-item__name">' + escapeHtml_(b.name) + '</span>' +
          '<span class="panel-item__sub">Frasco ' + (b.fmt === '30ml' ? '30 ml' : '100 ml') + '</span></div>' +
          '<span class="admin-panel__line-price">' + colones(b.price) + '</span>' +
        '</div>' +
        (hasInv ? concPickerHtml(b.pct, 'bottle', idx) + oilCostHtml(b.pct, fmtMl, 'bottle', idx) : '');
      panelSummary.appendChild(el);
    });
  }

  panelSummary.addEventListener('click', function (e) {
    var btn = e.target.closest('.conc-btn');
    if (!btn) return;
    var type = btn.dataset.type;
    var idx  = parseInt(btn.dataset.idx, 10);
    var pct  = parseFloat(btn.dataset.pct);

    if (type === 'decant') selection[idx].pct = pct;
    else bottles[idx].pct = pct;

    btn.closest('.conc-picker').querySelectorAll('.conc-btn').forEach(function (b) {
      b.classList.toggle('conc-btn--active', parseFloat(b.dataset.pct) === pct);
    });

    var item   = btn.closest('.admin-panel__item');
    var costEl = item && item.querySelector('.js-oil-cost');
    if (costEl) {
      var fmtMl = type === 'decant' ? 10 : (bottles[idx] && bottles[idx].fmt === '30ml' ? 30 : 100);
      costEl.textContent = ((pct / 100) * fmtMl).toFixed(1) + ' ml aceite';
    }
  });

  openPanelBtn.addEventListener('click', openPanel);
  closePanelBtn.addEventListener('click', function () { closePanel(false); });
  document.getElementById('js-panel-backdrop').addEventListener('click', function () { closePanel(false); });

  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && !adminPanelEl.hidden) closePanel(false);
  });

  registerBtn.addEventListener('click', function () {
    if (!canRegister()) return;
    var total = cartTotal();
    registerBtn.disabled    = true;
    registerBtn.textContent = 'Registrando...';

    var ref   = generateRef();
    var items = buildItems().map(function (i) { return i.label; }).join(' | ');
    var pago  = document.querySelector('input[name="pago"]:checked').value;
    var nota  = noteEl.value.trim();

    fetch(EXEC_URL, {
      method: 'POST',
      body: JSON.stringify({
        ref: ref, items: items, total: total,
        pago: pago, entrega: 'En sitio', canal: 'Local', cliente: nota, token: token
      })
    })
    .then(function (r) { return r.text(); })
    .then(function (txt) {
      registerBtn.textContent = 'Confirmar';
      if (txt.trim() === 'ok') {
        decrementSaleStock();
        showToast('Venta registrada \xb7 ' + ref + ' \xb7 ' + colones(total));
        resetCart();
        loadMetrics();
        syncInvDisplay();
        setTimeout(function () { closePanel(true); }, 2200);
      } else {
        showToast('Error (' + txt + '). Intent\xe1 de nuevo.', true);
        registerBtn.disabled = false;
      }
    })
    .catch(function () {
      registerBtn.textContent = 'Confirmar';
      showToast('Sin conexi\xf3n. Anot\xe1 la venta y registr\xe1 cuando tengas internet.', true);
      registerBtn.disabled = false;
    });
  });

  function resetCart() {
    selection = []; bottles = [];
    noteEl.value = '';
    var efCheck = document.querySelector('input[name="pago"][value="Efectivo"]');
    if (efCheck) efCheck.checked = true;
    syncCart();
  }

  function showToast(msg, isError) {
    toastEl.hidden      = true;
    toastEl.textContent = msg;
    toastEl.className   = 'pos__toast' + (isError ? ' pos__toast--error' : '');
    toastEl.getBoundingClientRect();
    toastEl.hidden = false;
    clearTimeout(toastEl._t);
    toastEl._t = setTimeout(function () { toastEl.hidden = true; }, 4000);
  }

  invListEl.addEventListener('click', function (e) {
    var btn = e.target.closest('.js-inv-oil-adj');
    if (!btn) return;
    var id       = btn.dataset.id;
    var delta_ml = parseFloat(btn.dataset.delta) || 0;
    if (!inventory[id]) inventory[id] = { oil_ml: 0 };
    inventory[id].oil_ml = Math.max(0, (inventory[id].oil_ml || 0) + delta_ml);
    syncInvDisplay();
    syncFragBtns();
    batchUpdateStock([{ key: id, delta_ml: delta_ml }]);
  });

  invListEl.addEventListener('change', function (e) {
    var oilInput = e.target.closest('.js-inv-oil');
    if (!oilInput) return;
    var id     = oilInput.dataset.id;
    var newOil = Math.max(0, parseFloat(oilInput.value) || 0);
    if (!inventory[id]) inventory[id] = { oil_ml: 0 };
    inventory[id].oil_ml = newOil;
    oilInput.value = newOil;
    syncInvDisplay();
    syncFragBtns();
    batchUpdateStock([{ key: id, set_oil_ml: newOil }]);
  });

  function fmtOil(ml) {
    ml = Math.round(ml);
    if (ml >= 1000) return (ml / 1000 % 1 === 0 ? ml / 1000 : (ml / 1000).toFixed(1)) + 'k';
    return ml;
  }

  function buildInvRow(frag) {
    var el  = document.createElement('div');
    el.className = 'dblock dblock--inv-mode';
    if (frag.name === topFragranceName) el.classList.add('dblock--best-seller');
    var id    = frag.id;
    var searchName = frag.name.toLowerCase();
    var entry = inventory[searchName];
    if (!entry && inventory._byKeyword) {
      var words = searchName.split(/\s+/);
      for (var w = 0; w < words.length; w++) {
        if (inventory._byKeyword[words[w]]) {
          entry = inventory._byKeyword[words[w]];
          break;
        }
      }
    }
    entry = entry || inventory[id] || { oil_ml: 0 };
    var oil   = entry.oil_ml || 0;

    var nameHtml = frag.brand
      ? '<span class="dblock__brand">' + frag.brand + '</span><h3 class="dblock__name">' + frag.name + '</h3>'
      : '<h3 class="dblock__name">' + frag.name + '</h3>';

    el.innerHTML =
      '<div class="dblock__top">' +
        '<div class="inv-stock-badge js-inv-total' + (oil > 0 && oil < LOW_OIL_ML ? ' inv-stock-badge--low' : '') + (oil <= 0 ? ' inv-stock-badge--empty' : '') + '" data-id="' + id + '">' + fmtOil(oil) + '</div>' +
        '<div class="inv-name-block">' + nameHtml + '</div>' +
      '</div>' +
      '<div class="inv-oil-zone">' +
        '<div class="inv-oil-value-row">' +
          '<input class="inv-oil-input js-inv-oil" data-id="' + id + '" type="number" value="' + oil + '" min="0" max="9999999" step="10" aria-label="Aceite en ml" inputmode="decimal">' +
          '<span class="inv-oil-unit">ml</span>' +
        '</div>' +
        '<div class="inv-oil-controls">' +
          '<button class="inv-adj inv-adj--minus js-inv-oil-adj" data-id="' + id + '" data-delta="-10" type="button" aria-label="Quitar 10 ml">−</button>' +
          '<button class="inv-adj inv-adj--plus js-inv-oil-adj" data-id="' + id + '" data-delta="10" type="button" aria-label="Agregar 10 ml">+</button>' +
        '</div>' +
      '</div>';

    return el;
  }

  function appendInvPage() {
    var start = invPage * PAGE_SIZE;
    var slice = invFilteredCatalog.slice(start, start + PAGE_SIZE);
    var frag  = document.createDocumentFragment();
    slice.forEach(function (f) { frag.appendChild(buildInvRow(f)); });
    invListEl.appendChild(frag);
    invPage++;
    if (invPage * PAGE_SIZE >= invFilteredCatalog.length && invObserver) {
      invObserver.disconnect();
      invObserver = null;
    }
  }

  function renderInvList(query) {
    var q = (query || '').trim().toLowerCase();
    invFilteredCatalog = catalog.filter(function (f) {
      if (!q) return true;
      var t = f.name.toLowerCase() + (f.brand ? ' ' + f.brand.toLowerCase() : '');
      return t.indexOf(q) !== -1;
    });

    invPage = 0;
    invListEl.innerHTML = '';

    if (!invFilteredCatalog.length) {
      var empty = document.createElement('p');
      empty.className = 'dblock-empty';
      empty.textContent = 'Sin resultados.';
      invListEl.appendChild(empty);
      return;
    }

    if (invObserver) { invObserver.disconnect(); invObserver = null; }
    appendInvPage();

    if (invFilteredCatalog.length > PAGE_SIZE) {
      invObserver = new IntersectionObserver(function (entries) {
        if (entries[0].isIntersecting) appendInvPage();
      }, { rootMargin: '120px' });
      invObserver.observe(invSentinel);
    }
  }

  function syncInvDisplay() {
    invListEl.querySelectorAll('.js-inv-total').forEach(function (el) {
      var oil = (inventory[el.dataset.id] || {}).oil_ml || 0;
      el.textContent = fmtOil(oil);
      el.classList.toggle('inv-stock-badge--low',  oil > 0 && oil < LOW_OIL_ML);
      el.classList.toggle('inv-stock-badge--empty', oil <= 0);
    });
    invListEl.querySelectorAll('.js-inv-oil').forEach(function (el) {
      el.value = (inventory[el.dataset.id] || {}).oil_ml || 0;
    });
  }

  document.addEventListener('keydown', function(e) {
    if (e.key === '/' && searchEl && !searchEl.contains(document.activeElement)) {
      e.preventDefault();
      searchEl.focus();
    }
  });

  (function init() {
    buildCatalog();
    var saved = getToken();
    if (saved) showApp(saved);
    else       showGate();
  })();

})();
